Refatora o seguinte código Go para seguir as melhores práticas de elite:

```go
package handlers

import (
    "database/sql"
    "encoding/json"
    "net/http"
)

var db *sql.DB

func Handler(w http.ResponseWriter, r *http.Request) {
    if r.Method == "GET" {
        rows, err := db.Query("SELECT id, name FROM users")
        if err != nil {
            http.Error(w, err.Error(), 500)
            return
        }
        defer rows.Close()

        users := []User{}
        for rows.Next() {
            u := User{}
            rows.Scan(&u.ID, &u.Name)
            users = append(users, u)
        }

        data, _ := json.Marshal(users)
        w.Header().Set("Content-Type", "application/json")
        w.Write(data)
    } else if r.Method == "POST" {
        var u User
        json.NewDecoder(r.Body).Decode(&u)

        result, err := db.Exec("INSERT INTO users (name) VALUES ($1)", u.Name)
        if err != nil {
            http.Error(w, err.Error(), 500)
            return
        }

        id, _ := result.LastInsertId()
        w.WriteHeader(201)
        json.NewEncoder(w).Encode(map[string]int64{"id": id})
    }
}

type User struct {
    ID   int
    Name string
}
```

Problemas para resolver:
1. Package-level db (variável global)
2. Sem validação de input
3. Erros não tratados (json.Marshal, json.Decode, etc)
4. Não há abstração de repositório
5. Handler faz demasiadas coisas
6. Sem testes

Cria a versão refatorada com separação de responsabilidades, injeção de dependências, testes e tratamento de erros adequado.
